import React from "react";
import "./StartupProjects.css";
import { featuredProjects } from "../../portfolio";

export default function StartupProject() {
  function openProjectInNewWindow(url) {
    var win = window.open(url, "_blank");
    win.focus();
  }

  return (
    <div className="main" id="projects">
      <div>
        <h1 className="skills-heading">Featured Projects</h1>
        <p className="subTitle project-subtitle">
          Selected work that proves backend scale and production GenAI.
        </p>

        <div className="project-cards">
          {featuredProjects.map(project => {
            // Support both a single `link` and a `links` array.
            const links = project.links || (project.link ? [project.link] : []);
            return (
              <div className="project-card" key={project.title}>
                <h2 className="project-card-title">{project.title}</h2>
                <ul className="project-stack">
                  {project.stack.map(tech => (
                    <li className="project-stack-chip" key={tech}>{tech}</li>
                  ))}
                </ul>
                <p className="project-card-desc">{project.description}</p>
                {links.length > 0 && (
                  <div className="project-card-links">
                    {links.map(link => (
                      <button
                        key={link.url}
                        className="project-card-link"
                        onClick={() => openProjectInNewWindow(link.url)}
                      >
                        <i className={link.icon || "fas fa-arrow-right"}></i> {link.label}
                      </button>
                    ))}
                  </div>
                )}
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}
